import tensorflow as tf
import numpy as np
import pandas as pd
import hashlib
import json
from datetime import datetime
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import os
from io import StringIO
import cv2
from sklearn.model_selection import train_test_split
from collections import Counter
import logging

app = Flask(__name__)
app.config['MAX_CONTENT_LENGTH'] = 50 * 1024 * 1024
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['MODEL_FOLDER'] = 'models'

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)
os.makedirs(app.config['MODEL_FOLDER'], exist_ok=True)

ALLOWED_EXTENSIONS = {'csv', 'jpg', 'jpeg', 'png'}
MAX_SAMPLES_PER_USER = 100
MAX_SAMPLES_PER_CLASS = 1000
MIN_SAMPLES_PER_CLASS = 10
ANOMALY_THRESHOLD = 3.0
MAX_CONTRIBUTION_RATE = 50
VALIDATION_SPLIT = 0.2

user_contributions = {}
class_distributions = {}
data_store = []
trusted_users = set()


def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS


def get_user_id(request):
    user_ip = request.remote_addr
    user_agent = request.headers.get('User-Agent', '')
    user_hash = hashlib.sha256(f"{user_ip}{user_agent}".encode()).hexdigest()
    return user_hash


def check_rate_limit(user_id):
    current_time = datetime.now()
    if user_id not in user_contributions:
        user_contributions[user_id] = {'count': 0, 'last_reset': current_time}
        return True
    
    time_diff = (current_time - user_contributions[user_id]['last_reset']).total_seconds()
    if time_diff > 3600:
        user_contributions[user_id] = {'count': 0, 'last_reset': current_time}
    
    if user_contributions[user_id]['count'] >= MAX_CONTRIBUTION_RATE:
        return False
    
    user_contributions[user_id]['count'] += 1
    return True


def validate_csv_structure(df):
    if df.empty:
        return False, "Empty CSV file"
    
    if len(df.columns) < 2:
        return False, "CSV must have at least 2 columns (features and label)"
    
    if df.isnull().sum().sum() > len(df) * 0.1:
        return False, "Too many missing values (>10%)"
    
    return True, "Valid"


def detect_label_poisoning(new_labels, existing_labels):
    if not existing_labels:
        return False
    
    new_label_dist = Counter(new_labels)
    existing_label_dist = Counter(existing_labels)
    
    for label, count in new_label_dist.items():
        if label in existing_label_dist:
            existing_ratio = existing_label_dist[label] / len(existing_labels)
            new_ratio = count / len(new_labels)
            if abs(new_ratio - existing_ratio) > 0.5:
                return True
    
    return False


def detect_statistical_anomalies(new_data, existing_data):
    if len(existing_data) < MIN_SAMPLES_PER_CLASS:
        return False
    
    existing_array = np.array(existing_data)
    new_array = np.array(new_data)
    
    existing_mean = np.mean(existing_array, axis=0)
    existing_std = np.std(existing_array, axis=0) + 1e-7
    
    z_scores = np.abs((new_array - existing_mean) / existing_std)
    
    if np.mean(z_scores) > ANOMALY_THRESHOLD:
        return True
    
    return False


def validate_image(image_path):
    try:
        img = cv2.imread(image_path)
        if img is None:
            return False, "Invalid image file"
        
        height, width = img.shape[:2]
        if height < 32 or width < 32 or height > 4096 or width > 4096:
            return False, "Image dimensions out of acceptable range"
        
        if len(img.shape) == 3 and img.shape[2] not in [1, 3, 4]:
            return False, "Invalid number of channels"
        
        pixel_mean = np.mean(img)
        pixel_std = np.std(img)
        if pixel_std < 1.0:
            return False, "Image has suspiciously low variance"
        
        return True, "Valid image"
    except Exception as e:
        return False, f"Image validation error: {str(e)}"


def sanitize_data(data):
    data = np.clip(data, -1e6, 1e6)
    data = np.nan_to_num(data, nan=0.0, posinf=1e6, neginf=-1e6)
    return data


def check_class_balance(labels):
    label_counts = Counter(labels)
    
    for label, count in label_counts.items():
        if count > MAX_SAMPLES_PER_CLASS:
            return False, f"Class {label} exceeds maximum samples"
    
    if len(label_counts) > 1:
        max_count = max(label_counts.values())
        min_count = min(label_counts.values())
        if max_count / min_count > 10:
            return False, "Severe class imbalance detected"
    
    return True, "Balanced"


def create_model(input_shape, num_classes):
    model = tf.keras.Sequential([
        tf.keras.layers.Input(shape=input_shape),
        tf.keras.layers.Dense(128, activation='relu'),
        tf.keras.layers.Dropout(0.3),
        tf.keras.layers.Dense(64, activation='relu'),
        tf.keras.layers.Dropout(0.3),
        tf.keras.layers.Dense(num_classes, activation='softmax')
    ])
    
    model.compile(
        optimizer='adam',
        loss='sparse_categorical_crossentropy',
        metrics=['accuracy']
    )
    
    return model


def create_image_model(input_shape, num_classes):
    model = tf.keras.Sequential([
        tf.keras.layers.Input(shape=input_shape),
        tf.keras.layers.Conv2D(32, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.Flatten(),
        tf.keras.layers.Dense(64, activation='relu'),
        tf.keras.layers.Dropout(0.5),
        tf.keras.layers.Dense(num_classes, activation='softmax')
    ])
    
    model.compile(
        optimizer='adam',
        loss='sparse_categorical_crossentropy',
        metrics=['accuracy']
    )
    
    return model


@app.route('/upload_csv', methods=['POST'])
def upload_csv():
    user_id = get_user_id(request)
    
    if not check_rate_limit(user_id):
        return jsonify({'error': 'Rate limit exceeded'}), 429
    
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if not allowed_file(file.filename):
        return jsonify({'error': 'Invalid file type'}), 400
    
    try:
        content = file.read().decode('utf-8')
        df = pd.read_csv(StringIO(content))
        
        valid, message = validate_csv_structure(df)
        if not valid:
            return jsonify({'error': message}), 400
        
        labels = df.iloc[:, -1].values
        features = df.iloc[:, :-1].values
        
        existing_labels = [item['label'] for item in data_store]
        if detect_label_poisoning(labels, existing_labels):
            logger.warning(f"Label poisoning detected from user {user_id}")
            return jsonify({'error': 'Suspicious label distribution detected'}), 400
        
        existing_features = [item['features'] for item in data_store if 'features' in item]
        if detect_statistical_anomalies(features, existing_features):
            logger.warning(f"Statistical anomaly detected from user {user_id}")
            return jsonify({'error': 'Statistical anomaly detected in data'}), 400
        
        balanced, message = check_class_balance(labels)
        if not balanced:
            return jsonify({'error': message}), 400
        
        features = sanitize_data(features)
        
        for i in range(len(features)):
            if len(data_store) >= MAX_SAMPLES_PER_USER * len(user_contributions):
                break
            data_store.append({
                'features': features[i],
                'label': labels[i],
                'user_id': user_id,
                'timestamp': datetime.now().isoformat()
            })
        
        return jsonify({
            'message': 'Data uploaded successfully',
            'samples_added': len(features),
            'total_samples': len(data_store)
        }), 200
        
    except Exception as e:
        logger.error(f"Error processing CSV: {str(e)}")
        return jsonify({'error': 'Error processing file'}), 500


@app.route('/upload_image', methods=['POST'])
def upload_image():
    user_id = get_user_id(request)
    
    if not check_rate_limit(user_id):
        return jsonify({'error': 'Rate limit exceeded'}), 429
    
    if 'file' not in request.files or 'label' not in request.form:
        return jsonify({'error': 'File and label required'}), 400
    
    file = request.files['file']
    label = request.form['label']
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if not allowed_file(file.filename):
        return jsonify({'error': 'Invalid file type'}), 400
    
    try:
        filename = secure_filename(file.filename)
        timestamp = datetime.now().strftime('%Y%m%d%H%M%S')
        unique_filename = f"{user_id[:8]}_{timestamp}_{filename}"
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], unique_filename)
        
        file.save(filepath)
        
        valid, message = validate_image(filepath)
        if not valid:
            os.remove(filepath)
            return jsonify({'error': message}), 400
        
        img = cv2.imread(filepath)
        img = cv2.resize(img, (128, 128))
        img = img / 255.0
        
        existing_labels = [item['label'] for item in data_store]
        if detect_label_poisoning([label], existing_labels):
            os.remove(filepath)
            logger.warning(f"Label poisoning detected from user {user_id}")
            return jsonify({'error': 'Suspicious label detected'}), 400
        
        data_store.append({
            'image_path': filepath,
            'image_data': img,
            'label': label,
            'user_id': user_id,
            'timestamp': datetime.now().isoformat()
        })
        
        return jsonify({
            'message': 'Image uploaded successfully',
            'total_samples': len(data_store)
        }), 200
        
    except Exception as e:
        logger.error(f"Error processing image: {str(e)}")
        if os.path.exists(filepath):
            os.remove(filepath)
        return jsonify({'error': 'Error processing image'}), 500


@app.route('/train', methods=['POST'])
def train_model():
    if len(data_store) < MIN_SAMPLES_PER_CLASS * 2:
        return jsonify({'error': 'Insufficient training data'}), 400
    
    try:
        has_images = 'image_data' in data_store[0]
        
        if has_images:
            images = np.array([item['image_data'] for item in data_store])
            labels = np.array([item['label'] for item in data_store])
            
            unique_labels = sorted(list(set(labels)))
            label_to_idx = {label: idx for idx, label in enumerate(unique_labels)}
            labels_encoded = np.array([label_to_idx[label] for label in labels])
            
            X_train, X_val, y_train, y_val = train_test_split(
                images, labels_encoded, test_size=VALIDATION_SPLIT, random_state=42
            )
            
            model = create_image_model(
                input_shape=images.shape[1:],
                num_classes=len(unique_labels)
            )
        else:
            features = np.array([item['features'] for item in data_store])
            labels = np.array([item['label'] for item in data_store])
            
            features = sanitize_data(features)
            
            unique_labels = sorted(list(set(labels)))
            label_to_idx = {label: idx for idx, label in enumerate(unique_labels)}
            labels_encoded = np.array([label_to_idx[label] for label in labels])
            
            X_train, X_val, y_train, y_val = train_test_split(
                features, labels_encoded, test_size=VALIDATION_SPLIT, random_state=42
            )
            
            model = create_model(
                input_shape=(features.shape[1],),
                num_classes=len(unique_labels)
            )
        
        early_stopping = tf.keras.callbacks.EarlyStopping(
            monitor='val_loss',
            patience=5,
            restore_best_weights=True
        )
        
        history = model.fit(
            X_train, y_train,
            validation_data=(X_val, y_val),
            epochs=50,
            batch_size=32,
            callbacks=[early_stopping],
            verbose=0
        )
        
        val_loss, val_accuracy = model.evaluate(X_val, y_val, verbose=0)
        
        model_path = os.path.join(
            app.config['MODEL_FOLDER'],
            f"model_{datetime.now().strftime('%Y%m%d%H%M%S')}.h5"
        )
        model.save(model_path)
        
        return jsonify({
            'message': 'Model trained successfully',
            'validation_accuracy': float(val_accuracy),
            'validation_loss': float(val_loss),
            'training_samples': len(X_train),
            'validation_samples': len(X_val),
            'model_path': model_path
        }), 200
        
    except Exception as e:
        logger.error(f"Error training model: {str(e)}")
        return jsonify({'error': 'Error training model'}), 500


